import React from 'react';
import styles from './JobCard.module.css';

const JobCard = ({ job, onClick, isFull }) => {
    return (
        <div className={styles.card} onClick={onClick}>
            <h3 className={styles.title}>{job.title}</h3>
            <p className={styles.company}>{job.company}</p>

            {/* Hanya tampilkan info detail jika variant full */}
            {isFull ? (
                <>
                    <p className={styles.salary}>📍 {job.location} • 💰 {job.salary}</p>
                    <p className={styles.desc}>{job.desc}</p>
                    <button className={styles.applyBtn}>Detail & Lamar</button>
                </>
            ) : (
                // Tampilan sederhana untuk Homepage
                <p className={styles.salary} style={{ fontSize: '12px' }}>{job.location} • {job.salary}</p>
            )}
        </div>
    );
};
export default JobCard;
